@Override
  public Object doWork(Object first, Object second) throws IOException{
    if(null == first){
      throw new IOException(String.format(Locale.ROOT,"Unable to %s(...) with a null numerator", constructingFactory.getFunctionName(getClass())));
    }

    if(null == second){
      throw new IOException(String.format(Locale.ROOT,"Unable to %s(...) with a null denominator", constructingFactory.getFunctionName(getClass())));
    }

    BigDecimal numerator = (BigDecimal)first;
    BigDecimal denominator = (BigDecimal)second;

    if(0 == denominator.compareTo(BigDecimal.ZERO)){
      throw new IOException(String.format(Locale.ROOT,"Unable to %s(...) with a 0 denominator", constructingFactory.getFunctionName(getClass())));
    }

    return numerator.divide(denominator, MathContext.DECIMAL64);
  },long_method

public class SortedByFacetOnCollectionFromLayoutProperties extends SortedByFacetAbstract {

    public static SortedByFacet create(Properties properties, FacetHolder holder) {
        final Class sortedBy = sortedBy(properties);
        return sortedBy != null? new SortedByFacetOnCollectionFromLayoutProperties(sortedBy, holder): null;
    }

    private SortedByFacetOnCollectionFromLayoutProperties(Class<? extends Comparator<?>> sortedBy, FacetHolder holder) {
        super(sortedBy, holder);
    }

    private static Class<?> sortedBy(Properties properties) {
        if(properties == null) {
            return null;
        }
        String sortedBy = Strings.emptyToNull(properties.getProperty("sortedBy"));
        if (sortedBy == null) {
            return null;
        }
        final Class<?> sortedByClass = ClassUtil.forName(sortedBy);
        if(sortedByClass == Comparator.class) {
            return null;
        }
        return sortedByClass;
    }

},god_class

public class RemoteClientActivator implements BundleActivator {
    @Override
    public void start(BundleContext bundleContext) throws Exception {
        final ClassLoader oldCl = Thread.currentThread().getContextClassLoader();
        // set the bundle classloader to avoid to go back to AppClassloader and not found imported classes
        Thread.currentThread().setContextClassLoader(getClass().getClassLoader());
        try {
            ClientUtil.invoke();
        } catch (Exception e) {
            System.out.println("error: " + e.getMessage());
        } finally {
            Thread.currentThread().setContextClassLoader(oldCl);
        }
    }

    @Override
    public void stop(BundleContext bundleContext) throws Exception {
        // no-op
    }
