private static class SpscArrayQueueReservoir extends AbstractReservoir
  {
    private final int maxSpinMillis = 10;
    private final SpscArrayQueue<Object> queue;

    private SpscArrayQueueReservoir(final String id, final int capacity)
    {
      super(id);
      queue = new SpscArrayQueue<>(capacity);
    }

    @Override
    public Tuple sweep()
    {
      Object o;
      final SpscArrayQueue<Object> queue = this.queue;
      final Sink<Object> sink = getSink();
      while ((o = queue.peek()) != null) {
        if (o instanceof Tuple) {
          return (Tuple)o;
        }
        count++;
        sink.put(queue.poll());
      }
      return null;
    }

    @Override
    public boolean add(Object o)
    {
      return queue.add(o);
    }

    @Override
    public Object remove()
    {
      return queue.remove();
    }

    @Override
    public Object peek()
    {
      return queue.peek();
    }

    @Override
    public int size(final boolean dataTupleAware)
    {
      return queue.size();
    }

    @Override
    public int capacity()
    {
      return queue.capacity();
    }

    @Override
    public int drainTo(final Collection<? super Object> container)
    {
      return queue.drain(new MessagePassingQueue.Consumer<Object>()
      {
        @Override
        public void accept(Object o)
        {
          container.add(o);
        }
      });
    }

    @Override
    public boolean offer(Object o)
    {
      return queue.offer(o);
    }

    @Override
    public void put(Object o) throws InterruptedException
    {
      long spinMillis = 0;
      final SpscArrayQueue<Object> queue = this.queue;
      while (!queue.offer(o)) {
        sleep(spinMillis);
        spinMillis = Math.min(maxSpinMillis, spinMillis + 1);
      }
    }

    @Override
    public boolean offer(Object o, long timeout, TimeUnit unit) throws InterruptedException
    {
      throw new UnsupportedOperationException();
    }

    @Override
    public Object take() throws InterruptedException
    {
      throw new UnsupportedOperationException();
    }

    @Override
    public Object poll(long timeout, TimeUnit unit) throws InterruptedException
    {
      throw new UnsupportedOperationException();
    }

    @Override
    public int remainingCapacity()
    {
      final SpscArrayQueue<Object> queue = this.queue;
      return queue.capacity() - queue.size();
    }

    @Override
    public boolean remove(Object o)
    {
      return queue.remove(o);
    }

    @Override
    public boolean contains(Object o)
    {
      return queue.contains(o);
    }

    @Override
    public int drainTo(final Collection<? super Object> collection, int maxElements)
    {
      return queue.drain(new MessagePassingQueue.Consumer<Object>()
      {
        @Override
        public void accept(Object o)
        {
          collection.add(o);
        }
      }, maxElements);
    }

    @Override
    public Object poll()
    {
      return queue.poll();
    }

    @Override
    public Object element()
    {
      return queue.element();
    }

    @Override
    public boolean isEmpty()
    {
      return queue.peek() == null;
    }

    @Override
    public Iterator<Object> iterator()
    {
      return queue.iterator();
    }

    @Override
    public Object[] toArray()
    {
      return queue.toArray();
    }

    @Override
    public <T> T[] toArray(T[] a)
    {
      return queue.toArray(a);
    }

    @Override
    public boolean containsAll(Collection<?> c)
    {
      return queue.containsAll(c);
    }

    @Override
    public boolean addAll(Collection<?> c)
    {
      return queue.addAll(c);
    }

    @Override
    public boolean removeAll(Collection<?> c)
    {
      return queue.removeAll(c);
    }

    @Override
    public boolean retainAll(Collection<?> c)
    {
      return queue.retainAll(c);
    }

    @Override
    public int size()
    {
      return queue.size();
    }

    @Override
    public void clear()
    {
      queue.clear();
    }

    protected SpscArrayQueue<Object> getQueue()
    {
      return queue;
    }

  },god_class

private static void renderChildren(List<Tree> children, int indent,
        boolean parentLabelNull, StringBuilder sb) {
      boolean firstSibling = true;
      boolean leftSibIsPreTerm = true; // counts as true at beginning
      for (Tree child : children) {
        renderTree(child, indent, parentLabelNull, firstSibling, leftSibIsPreTerm, false, sb);
        leftSibIsPreTerm = child.isPreTerminal();
        firstSibling = false;
      }
    },long_method

@InterfaceAudience.Public
@InterfaceStability.Stable
public class LazyOutputFormat <K,V> extends FilterOutputFormat<K, V> {
  public static String OUTPUT_FORMAT = 
    "mapreduce.output.lazyoutputformat.outputformat";
  /**
   * Set the underlying output format for LazyOutputFormat.
   * @param job the {@link Job} to modify
   * @param theClass the underlying class
   */
  @SuppressWarnings("unchecked")
  public static void  setOutputFormatClass(Job job, 
                                     Class<? extends OutputFormat> theClass) {
      job.setOutputFormatClass(LazyOutputFormat.class);
      job.getConfiguration().setClass(OUTPUT_FORMAT, 
          theClass, OutputFormat.class);
  }

  @SuppressWarnings("unchecked")
  private void getBaseOutputFormat(Configuration conf) 
  throws IOException {
    baseOut =  ((OutputFormat<K, V>) ReflectionUtils.newInstance(
      conf.getClass(OUTPUT_FORMAT, null), conf));
    if (baseOut == null) {
      throw new IOException("Output Format not set for LazyOutputFormat");
    }
  }

  @Override
  public RecordWriter<K, V> getRecordWriter(TaskAttemptContext context)
  throws IOException, InterruptedException {
    if (baseOut == null) {
      getBaseOutputFormat(context.getConfiguration());
    }
    return new LazyRecordWriter<K, V>(baseOut, context);
  }

  @Override
  public void checkOutputSpecs(JobContext context) 
  throws IOException, InterruptedException {
    if (baseOut == null) {
      getBaseOutputFormat(context.getConfiguration());
    }
   super.checkOutputSpecs(context);
  }

  @Override
  public OutputCommitter getOutputCommitter(TaskAttemptContext context) 
  throws IOException, InterruptedException {
    if (baseOut == null) {
      getBaseOutputFormat(context.getConfiguration());
    }
    return super.getOutputCommitter(context);
  }

  /**
   * A convenience class to be used with LazyOutputFormat
   */
  private static class LazyRecordWriter<K,V> extends FilterRecordWriter<K,V> {

    final OutputFormat<K,V> outputFormat;
    final TaskAttemptContext taskContext;

    public LazyRecordWriter(OutputFormat<K,V> out, 
                            TaskAttemptContext taskContext)
    throws IOException, InterruptedException {
      this.outputFormat = out;
      this.taskContext = taskContext;
    }

    @Override
    public void write(K key, V value) throws IOException, InterruptedException {
      if (rawWriter == null) {
        rawWriter = outputFormat.getRecordWriter(taskContext);
      }
      rawWriter.write(key, value);
    }

    @Override
    public void close(TaskAttemptContext context) 
    throws IOException, InterruptedException {
      if (rawWriter != null) {
        rawWriter.close(context);
      }
    }

  }
},god_class

