public static class get_call extends org.apache.thrift.async.TAsyncMethodCall<TResult> {
      private java.nio.ByteBuffer table;
      private TGet tget;
      public get_call(java.nio.ByteBuffer table, TGet tget, org.apache.thrift.async.AsyncMethodCallback<TResult> resultHandler, org.apache.thrift.async.TAsyncClient client, org.apache.thrift.protocol.TProtocolFactory protocolFactory, org.apache.thrift.transport.TNonblockingTransport transport) throws org.apache.thrift.TException {
        super(client, protocolFactory, transport, resultHandler, false);
        this.table = table;
        this.tget = tget;
      }

      public void write_args(org.apache.thrift.protocol.TProtocol prot) throws org.apache.thrift.TException {
        prot.writeMessageBegin(new org.apache.thrift.protocol.TMessage("get", org.apache.thrift.protocol.TMessageType.CALL, 0));
        get_args args = new get_args();
        args.setTable(table);
        args.setTget(tget);
        args.write(prot);
        prot.writeMessageEnd();
      }

      public TResult getResult() throws TIOError, org.apache.thrift.TException {
        if (getState() != org.apache.thrift.async.TAsyncMethodCall.State.RESPONSE_READ) {
          throw new java.lang.IllegalStateException("Method call not finished!");
        }
        org.apache.thrift.transport.TMemoryInputTransport memoryTransport = new org.apache.thrift.transport.TMemoryInputTransport(getFrameBuffer().array());
        org.apache.thrift.protocol.TProtocol prot = client.getProtocolFactory().getProtocol(memoryTransport);
        return (new Client(prot)).recv_get();
      }
    },god_class

static final class SymbolComparator implements Comparator {

		/* (non-Javadoc)
		 * @see java.util.Comparator#compare(java.lang.Object, java.lang.Object)
		 */
		public int compare(Object arg0, Object arg1) {

			long addr0=0;
			long addr1=0;
			// arg0 and arg1 will be Symbol objects 
			if (arg0 instanceof Symbol) {
				Symbol S0 = (Symbol) arg0;
				Symbol S1 = (Symbol) arg1;
				addr0 = S0.symbolStart;
				addr1 = S1.symbolStart;
			} else {
				addr0 = ((Long)arg0).longValue();
				addr1 = ((Long)arg1).longValue();
			}

			// both +ve
			if (addr0 >= 0 && addr1 >=0) {
				if (addr0 == addr1) return 0;
				if (addr0 < addr1) return -1;
				return 1;
			}

			// both -ve 
			if (addr0 < 0 && addr1 < 0) {
				if (addr0 == addr1) return 0;
				if (addr0 < addr1) return 1;
				return -1;
			}

			if (addr0 < 0 && addr1 >=0) {
				return 1;
			}

			return -1;
		}

	},god_class

