public class RandomForestClassifierTrainer
    extends RandomForestTrainer<ObjectHistogram<BootstrappedVector>, GiniHistogram, RandomForestClassifierTrainer> {
    /** Label mapping. */
    private Map<Double, Integer> lblMapping = new HashMap<>();

    /**
     * Constructs an instance of RandomForestClassifierTrainer.
     *
     * @param meta Features meta.
     */
    public RandomForestClassifierTrainer(List<FeatureMeta> meta) {
        super(meta);
    }

    /** {@inheritDoc} */
    @Override protected RandomForestClassifierTrainer instance() {
        return this;
    }

    /**
     * Aggregates all unique labels from dataset and assigns integer id value for each label.
     * This id can be used as index in arrays or lists.
     *
     * @param dataset Dataset.
     * @return true if initialization was done.
     */
    @Override protected boolean init(Dataset<EmptyContext, BootstrappedDatasetPartition> dataset) {
        Set<Double> uniqLabels = dataset.compute(
            x -> {
                Set<Double> labels = new HashSet<>();
                for (int i = 0; i < x.getRowsCount(); i++)
                    labels.add(x.getRow(i).label());
                return labels;
            },
            (l, r) -> {
                if (l == null)
                    return r;
                if (r == null)
                    return l;
                Set<Double> lbls = new HashSet<>();
                lbls.addAll(l);
                lbls.addAll(r);
                return lbls;
            }
        );

        if(uniqLabels == null)
            return false;

        int i = 0;
        for (Double label : uniqLabels)
            lblMapping.put(label, i++);

        return super.init(dataset);
    }

    /** {@inheritDoc} */
    @Override protected ModelsComposition buildComposition(List<TreeRoot> models) {
        return new ModelsComposition(models, new OnMajorityPredictionsAggregator());
    }

    /** {@inheritDoc} */
    @Override protected ImpurityHistogramsComputer<GiniHistogram> createImpurityHistogramsComputer() {
        return new GiniHistogramsComputer(lblMapping);
    }

    /** {@inheritDoc} */
    @Override protected LeafValuesComputer<ObjectHistogram<BootstrappedVector>> createLeafStatisticsAggregator() {
        return new ClassifierLeafValuesComputer(lblMapping);
    }

    /** {@inheritDoc} */
    @Override public RandomForestClassifierTrainer withEnvironmentBuilder(LearningEnvironmentBuilder envBuilder) {
        return (RandomForestClassifierTrainer)super.withEnvironmentBuilder(envBuilder);
    }
},god_class

public final class MoreStrings {

  /** Utility class: do not instantiate. */
  private MoreStrings() {}

  /**
   * Joins the les passed in with the platform line separator.
   *
   * @param lines the lines that need to be joined.
   * @return String, containing the joined lines using the platform line separator as delimiter.
   */
  public static String linesToText(String... lines) {
    return String.join(System.lineSeparator(), lines);
  }

  public static boolean isEmpty(CharSequence sequence) {
    return sequence.length() == 0;
  }

  public static String withoutSuffix(String str, String suffix) {
    Preconditions.checkArgument(str.endsWith(suffix), "%s must end with %s", str, suffix);
    return str.substring(0, str.length() - suffix.length());
  }

  public static String capitalize(String str) {
    if (!str.isEmpty()) {
      return str.substring(0, 1).toUpperCase() + str.substring(1);
    } else {
      return "";
    }
  }

  public static int getLevenshteinDistance(String str1, String str2) {
    if (str1.length() < str2.length()) {
      // ensure that str2 is always the smallest one to make space complexity O(min(|str1|, |str2|)
      return getLevenshteinDistance(str2, str1);
    }

    // reduce memory usage by storing only the last 2 rows of the table
    int previous = 0;
    int[][] levenshteinDist = new int[2][str2.length() + 1];

    for (int j = 0; j <= str2.length(); j++) {
      levenshteinDist[previous][j] = j;
    }

    for (int i = 1; i <= str1.length(); i++, previous = 1 - previous) {
      int current = 1 - previous;
      levenshteinDist[current][0] = i;
      for (int j = 1; j <= str2.length(); j++) {
        if (str1.charAt(i - 1) == str2.charAt(j - 1)) {
          levenshteinDist[current][j] = levenshteinDist[previous][j - 1];
        } else {
          levenshteinDist[current][j] =
              Math.min(
                      levenshteinDist[previous][j],
                      Math.min(levenshteinDist[current][j - 1], levenshteinDist[previous][j - 1]))
                  + 1;
        }
      }
    }

    return levenshteinDist[previous][str2.length()];
  }

  public static String regexPatternForAny(String... values) {
    return regexPatternForAny(Arrays.asList(values));
  }

  public static String regexPatternForAny(Iterable<String> values) {
    return "((?:" + Joiner.on(")|(?:").join(values) + "))";
  }

  public static boolean endsWithIgnoreCase(String str, String suffix) {
    if (str.length() < suffix.length()) {
      return false;
    }

    return str.substring(str.length() - suffix.length()).equalsIgnoreCase(suffix);
  }

  public static Optional<String> stripPrefix(String s, String prefix) {
    return s.startsWith(prefix) ? Optional.of(s.substring(prefix.length())) : Optional.empty();
  }

  public static Optional<String> stripSuffix(String s, String suffix) {
    return s.endsWith(suffix)
        ? Optional.of(s.substring(0, s.length() - suffix.length()))
        : Optional.empty();
  }

  public static String truncatePretty(String data) {
    int keepFirstChars = 10000;
    int keepLastChars = 10000;
    String truncateMessage = "...\n<truncated>\n...";
    return truncateMiddle(data, keepFirstChars, keepLastChars, truncateMessage);
  }

  public static String truncateMiddle(
      String data, int keepFirstChars, int keepLastChars, String truncateMessage) {
    if (data.length() <= keepFirstChars + keepLastChars + truncateMessage.length()) {
      return data;
    }
    return data.substring(0, keepFirstChars)
        + truncateMessage
        + data.substring(data.length() - keepLastChars);
  }

  public static ImmutableList<String> lines(String data) throws IOException {
    return CharSource.wrap(data).readLines();
  }

  /** Compare two strings lexicographically. */
  public static int compareStrings(String a, String b) {
    if (a == b) {
      return 0;
    }
    return a.compareTo(b);
  }

  /**
   * @return The spelling suggestion for the {@code input} based on its Levenstein distance from a
   *     list of available {@code options}.
   */
  public static List<String> getSpellingSuggestions(
      String input, Collection<String> options, int maxDistance) {
    return options
        .stream()
        .map(option -> new Pair<>(option, MoreStrings.getLevenshteinDistance(input, option)))
        .filter(pair -> pair.getSecond() <= maxDistance)
        .sorted(Comparator.comparing(Pair::getSecond))
        .map(Pair::getFirst)
        .collect(ImmutableList.toImmutableList());
  }

  /** Removes carriage return characters from the string with preserving new line characters. */
  public static String replaceCR(String text) {
    return text.replace("\r\n", "\n").replace('\r', '\n');
  }
},god_class

private static class Polyfill {
    /**
     * The language version at (or above) which the native symbol is
     * available and sufficient.  If the language out flag is at least
     * as high as {@code nativeVersion} then no rewriting will happen.
     */
    final FeatureSet nativeVersion;

    /**
     * The required language version for the polyfill to work.  This
     * should not be higher than {@code nativeVersion}, but may be the same
     * in cases where there is no polyfill provided.  This is used to
     * emit a warning if the language out flag is too low.
     */
    final FeatureSet polyfillVersion;

    /**
     * Runtime library to inject for the polyfill, e.g. "es6/map".
     */
    final String library;

    Polyfill(FeatureSet nativeVersion, FeatureSet polyfillVersion, String library) {
      this.nativeVersion = nativeVersion;
      this.polyfillVersion = polyfillVersion;
      this.library = library;
    }
  },data_class

