public class AvroWrapper<T> {
  private T datum;

  /** Wrap null. Construct {@link AvroWrapper} wrapping no datum. */
  public AvroWrapper() { this(null); }

  /** Wrap a datum. */
  public AvroWrapper(T datum) { this.datum = datum; }

  /** Return the wrapped datum. */
  public T datum() { return datum; }

  /** Set the wrapped datum. */
  public void datum(T datum) { this.datum = datum; }

  @Override
  public int hashCode() {
    return (datum == null) ? 0 : datum.hashCode();
  }

  @Override
  public boolean equals(Object obj) {
    if (this == obj)
      return true;
    if (obj == null)
      return false;
    if (getClass() != obj.getClass())
      return false;
    AvroWrapper that = (AvroWrapper)obj;
    if (this.datum == null) {
      return that.datum == null;
    } else return datum.equals(that.datum);
  }

  /** Get the wrapped datum as JSON. */
  @Override
  public String toString() {
    return datum.toString();
  }
},god_class

@Override
    public List<Permission> sessionPermissions(Session session)
        throws SecurityException
    {
        VUtil.assertNotNull(session, GlobalErrIds.USER_SESS_NULL, CLS_NM + ".sessionPermissions");
        List<Permission> retPerms;
        FortRequest request = new FortRequest();
        request.setContextId(this.contextId);
        request.setSession(session);
        String szRequest = RestUtils.marshal(request);
        String szResponse = RestUtils.getInstance().post(szRequest, HttpIds.ADMIN_PERMS);
        FortResponse response = RestUtils.unmarshall(szResponse);
        if (response.getErrorCode() == 0)
        {
            retPerms = response.getEntities();
            Session outSession = response.getSession();
            session.copy(outSession);
        }
        else
        {
            throw new SecurityException(response.getErrorCode(), response.getErrorMessage());
        }
        return retPerms;
    },feature_envy

