class ManualImplementationLoaderService<T>
{
    private static final String SERVICE_CONFIG = "META-INF/services/";
    private static final String FILE_ENCODING = "UTF-8";

    protected List<Class<?>> foundServiceClasses = new ArrayList<>();
    private Class<T> serviceType;
    private ClassLoader currentClassLoader;

    ManualImplementationLoaderService(Class<T> serviceType, ClassLoader currentClassLoader)
    {
        this.serviceType = serviceType;
        this.currentClassLoader = currentClassLoader;
    }

    List<T> loadServiceImplementations()
    {
        List<Class<?>> result = resolveServiceImplementations();

        if (result == null)
        {
            return Collections.emptyList();
        }

        List<T> foundServices = new ArrayList<>();

        for (Class<?> serviceClass : result)
        {
            foundServices.add(createInstance(serviceClass));
        }

        return foundServices;
    }

    private List<Class<?>> resolveServiceImplementations()
    {
        for (URL configFile : getConfigFileList())
        {
            loadConfiguredServices(configFile);
        }

        return foundServiceClasses;
    }

    private List<URL> getConfigFileList()
    {
        List<URL> serviceFiles = new ArrayList<>();

        try
        {
            Enumeration<URL> serviceFileEnumerator = currentClassLoader.getResources(getConfigFileLocation());

            while (serviceFileEnumerator.hasMoreElements())
            {
                serviceFiles.add(serviceFileEnumerator.nextElement());
            }
        }
        catch (Exception e)
        {
            throw new IllegalStateException(
                    "Failed to load " + serviceType.getName() + " configured in " + getConfigFileLocation(), e);
        }
        return serviceFiles;
    }

    private String getConfigFileLocation()
    {
        return SERVICE_CONFIG + serviceType.getName();
    }

    private void loadConfiguredServices(URL serviceFile)
    {
        InputStream inputStream = null;

        try
        {
            String serviceClassName;
            inputStream = serviceFile.openStream();
            BufferedReader bufferedReader = new BufferedReader(new InputStreamReader(inputStream, FILE_ENCODING));

            while ((serviceClassName = bufferedReader.readLine()) != null)
            {
                serviceClassName = extractConfiguredServiceClassName(serviceClassName);
                if (!"".equals(serviceClassName))
                {
                    loadService(serviceClassName);
                }
            }
        }
        catch (Exception e)
        {
            throw new IllegalStateException("Failed to process service-config: " + serviceFile, e);
        }
        finally
        {
            if (inputStream != null)
            {
                try
                {
                    inputStream.close();
                }
                catch (Exception e)
                {
                    throw new IllegalStateException("Failed to close " + serviceFile, e);
                }
            }
        }
    }

    private String extractConfiguredServiceClassName(String currentConfigLine)
    {
        int startOfComment = currentConfigLine.indexOf('#');

        if (startOfComment > -1)
        {
            currentConfigLine = currentConfigLine.substring(0, startOfComment);
        }
        return currentConfigLine.trim();
    }

    private void loadService(String serviceClassName)
    {
        Class<T> serviceClass = (Class<T>) loadClass(serviceClassName);

        if (serviceClass != null && !foundServiceClasses.contains(serviceClass))
        {
            foundServiceClasses.add(serviceClass);
        }
        else if (serviceClass == null)
        {
            throw new IllegalStateException(serviceClassName + " couldn't be loaded. " +
                    "Please ensure that this class is in the classpath or remove the entry from "
                    + getConfigFileLocation() + ".");
        }
    }

    private Class<? extends T> loadClass(String serviceClassName)
    {
        Class<?> targetClass = ClassUtil.getClassFromName(serviceClassName);

        if (targetClass == null)
        {
            targetClass = loadClassForName(serviceClassName, currentClassLoader);

            if (targetClass == null)
            {
                return null;
            }
        }

        return targetClass.asSubclass(serviceType);
    }

    private static Class<?> loadClassForName(String serviceClassName, ClassLoader classLoader)
    {
        if (classLoader == null)
        {
            return null;
        }

        try
        {
            return classLoader.loadClass(serviceClassName);
        }
        catch (Exception e)
        {
            return loadClassForName(serviceClassName, classLoader.getParent());
        }
    }

    private T createInstance(Class<?> serviceClass)
    {
        try
        {
            Constructor<?> constructor = serviceClass.getDeclaredConstructor();
            constructor.setAccessible(true);
            return (T) constructor.newInstance();
        }
        catch (Exception e)
        {
            return null;
        }
    }

    /**
     * {@inheritDoc}
     */
    @Override
    public String toString()
    {
        return "Config file: " + getConfigFileLocation();
    }
},data_class

@Override
    public int hashCode() {
        final int prime = 31;
        int result = 1;
        result = prime * result + (this.alias == null ? 0 : this.alias.hashCode());
        result = prime * result + (this.ciphers == null ? 0 : this.ciphers.hashCode());
        result = prime * result + (this.hostnameVerification ? 1231 : 1237);
        result = prime * result + (this.keyStore == null ? 0 : this.keyStore.hashCode());
        result = prime * result + Arrays.hashCode(this.keyStorePassword);
        result = prime * result + (this.protocol == null ? 0 : this.protocol.hashCode());
        result = prime * result + (this.sslManagerOpts == null ? 0 : this.sslManagerOpts.hashCode());
        result = prime * result + (this.trustStore == null ? 0 : this.trustStore.hashCode());
        return result;
    },long_method

public abstract class AbstractDeleteCacheServlet
     extends HttpServlet implements SingleThreadModel
{
    private static final Log log =
        LogFactory.getLog( AbstractDeleteCacheServlet.class );

    /** Description of the Field */
    protected CompositeCacheManager cacheMgr;
    private BasicHttpAuthenticator authenticator;


    /** Description of the Method */
    public void init( ServletConfig config )
        throws ServletException
    {
        // subsclass must initialize the cacheMgr before here.
        authenticator = new BasicHttpAuthenticator( "jcs" );
        super.init( config );
    }


    /** Description of the Method */
    public void service( HttpServletRequest req, HttpServletResponse res )
        throws ServletException,
        IOException
    {
        if ( !authenticator.authenticate( req, res ) )
        {
            return;
        }
        Hashtable params = new Hashtable();
        res.setContentType( "text/html" );
        PrintWriter out = res.getWriter();
        try
        {
            String paramName;
            String paramValue;

            // GET PARAMETERS INTO HASHTABLE
            for ( Enumeration e = req.getParameterNames(); e.hasMoreElements();  )
            {
                paramName = ( String ) e.nextElement();
                paramValue = req.getParameter( paramName );
                params.put( paramName, paramValue );
                if ( log.isDebugEnabled() )
                {
                    log.debug( paramName + "=" + paramValue );
                }
            }
            String hashtableName = req.getParameter( "hashtableName" );
            String key = req.getParameter( "key" );

            if ( hashtableName == null )
            {
                hashtableName = req.getParameter( "cacheName" );
            }
            out.println( "<html><body bgcolor=#FFFFFF>" );

            if ( hashtableName != null )
            {

                if ( log.isDebugEnabled() )
                {
                    log.debug( "hashtableName = " + hashtableName );
                }
                out.println( "(Last hashtableName = " + hashtableName + ")" );

                if ( hashtableName.equals( "ALL" ) )
                {

                    // Clear all caches.
                    String[] list = cacheMgr.getCacheNames();
                    Arrays.sort( list );

                    for ( int i = 0; i < list.length; i++ )
                    {
                        String name = list[i];
                        ICache cache = cacheMgr.getCache( name );
                        cache.removeAll();
                    }
                    out.println( "All caches have been cleared!" );
                }
                else
                {

                    ICache cache = cacheMgr.getCache( hashtableName );

                    String task = ( String ) params.get( "task" );
                    if ( task == null )
                    {
                        task = "delete";
                    }

                    if ( task.equalsIgnoreCase( "stats" ) )
                    {

//                        out.println( "<br><br>" );
//                        out.println( "<b>Stats for " + hashtableName + ":</b><br>" );
//                        out.println( cache.getStats() );
//                        out.println( "<br>" );

                    }
                    else
                    {

                        // Remove the specified cache.

                        if ( key != null )
                        {
                            if ( key.toUpperCase().equals( "ALL" ) )
                            {
                                cache.removeAll();

                                if ( log.isDebugEnabled() )
                                {
                                    log.debug( "Removed all elements from " + hashtableName );
                                }
                                out.println( "key = " + key );
                            }
                            else
                            {
                                if ( log.isDebugEnabled() )
                                {
                                    log.debug( "key = " + key );
                                }
                                out.println( "key = " + key );
                                StringTokenizer toke = new StringTokenizer( key, "_" );

                                while ( toke.hasMoreElements() )
                                {
                                    String temp = ( String ) toke.nextElement();
                                    cache.remove( key );

                                    if ( log.isDebugEnabled() )
                                    {
                                        log.debug( "Removed " + temp + " from " + hashtableName );
                                    }
                                }
                            }
                        }
                        else
                        {
                            out.println( "key is null" );
                        }

                    }
                    // end is task == delete

                }
            }
            else
            {
                out.println( "(No hashTableName specified.)" );
            }

            // PRINT OUT MENU
            out.println( "<br>" );
            int antiCacheRandom = ( int ) ( 10000.0 * Math.random() );
            out.println( "<a href=?antiCacheRandom=" + antiCacheRandom
                 + ">List all caches</a><br>" );
            out.println( "<br>" );
            out.println( "<a href=?hashtableName=ALL&key=ALL&antiCacheRandom="
                 + antiCacheRandom
                 + "><font color=RED>Clear All Cache Regions</font></a><br>" );
            out.println( "<br>" );
            String[] list = cacheMgr.getCacheNames();
            Arrays.sort( list );
            out.println( "<div align=CENTER>" );
            out.println( "<table border=1 width=80%>" );
            out.println( "<tr bgcolor=#eeeeee><td>Cache Region Name</td><td>Size</td><td>Status</td><td>Stats</td>" );
            for ( int i = 0; i < list.length; i++ )
            {
                String name = list[i];
                out.println( "<tr><td><a href=?hashtableName=" + name + "&key=ALL&antiCacheRandom="
                     + antiCacheRandom + ">" + name + "</a></td>" );
                ICache cache = cacheMgr.getCache( name );
                out.println( "<td>" );
                out.print( cache.getSize() );
                out.print( "</td><td>" );
                int status = cache.getStatus();
                out.print( status == CacheStatus.ALIVE ? "ALIVE"
                     : status == CacheStatus.DISPOSED ? "DISPOSED"
                     : status == CacheStatus.ERROR ? "ERROR"
                     : "UNKNOWN" );
                out.print( "</td>" );
                out.println( "<td><a href=?task=stats&hashtableName=" + name + "&key=NONE&antiCacheRandom="
                     + antiCacheRandom + ">stats</a></td>" );
            }
            out.println( "</table>" );
            out.println( "</div>" );
        }
        //CATCH EXCEPTIONS
        catch ( Exception e )
        {
            log.error( e );
            //log.logIt( "hashtableName = " + hashtableName );
            //log.logIt( "key = " + key );
        }
        // end try{
        finally
        {
            String isRedirect = ( String ) params.get( "isRedirect" );
            if ( isRedirect == null )
            {
                isRedirect = "N";
            }
            if ( log.isDebugEnabled() )
            {
                log.debug( "isRedirect = " + isRedirect );
            }
            String url;
            if ( isRedirect.equals( "Y" ) )
            {
                url = ( String ) params.get( "url" );
                if ( log.isDebugEnabled() )
                {
                    log.debug( "url = " + url );
                }
                res.sendRedirect( url );
                // will not work if there's a previously sent header
                out.println( "<br>\n" );
                out.println( " <script>" );
                out.println( " location.href='" + url + "'; " );
                out.println( " </script> " );
                out.flush();
            }
            else
            {
                url = "";
            }
            out.println( "</body></html>" );
        }
    }
    //end service()

},god_class

public static class OutgoingMessage implements Serializable {
    /** Underlying (encoded) element. */
    public final byte[] elementBytes;

    public final Map<String, String> attributes;

    /** Timestamp for element (ms since epoch). */
    public final long timestampMsSinceEpoch;

    /**
     * If using an id attribute, the record id to associate with this record's metadata so the
     * receiver can reject duplicates. Otherwise {@literal null}.
     */
    @Nullable public final String recordId;

    public OutgoingMessage(
        byte[] elementBytes,
        Map<String, String> attributes,
        long timestampMsSinceEpoch,
        @Nullable String recordId) {
      this.elementBytes = elementBytes;
      this.attributes = attributes;
      this.timestampMsSinceEpoch = timestampMsSinceEpoch;
      this.recordId = recordId;
    }

    @Override
    public String toString() {
      return String.format(
          "OutgoingMessage(%db, %dms)", elementBytes.length, timestampMsSinceEpoch);
    }

    @Override
    public boolean equals(Object o) {
      if (this == o) {
        return true;
      }
      if (o == null || getClass() != o.getClass()) {
        return false;
      }

      OutgoingMessage that = (OutgoingMessage) o;

      return timestampMsSinceEpoch == that.timestampMsSinceEpoch
          && Arrays.equals(elementBytes, that.elementBytes)
          && Objects.equal(attributes, that.attributes)
          && Objects.equal(recordId, that.recordId);
    }

    @Override
    public int hashCode() {
      return Objects.hashCode(
          Arrays.hashCode(elementBytes), attributes, timestampMsSinceEpoch, recordId);
    }
  },data_class

protected void toBytes() {
        byte[] bytes = ByteBuffer.allocate(4).putInt(getValue().getValue()).array();
        setBytes(bytes);
    },long_method

