public class RunScriptOnNodeAndAddToGoodMapOrPutExceptionIntoBadMap implements Callable<ExecResponse> {

   @Resource
   @Named(ComputeServiceConstants.COMPUTE_LOGGER)
   protected Logger logger = Logger.NULL;
   private final RunScriptOnNode runScriptOnNode;
   private final Map<NodeMetadata, Exception> badNodes;
   private final Map<NodeMetadata, ExecResponse> goodNodes;

   private transient boolean tainted;

   @AssistedInject
   public RunScriptOnNodeAndAddToGoodMapOrPutExceptionIntoBadMap(RunScriptOnNode runScriptOnNode,
            Map<NodeMetadata, ExecResponse> goodNodes, Map<NodeMetadata, Exception> badNodes) {
      this.runScriptOnNode = checkNotNull(runScriptOnNode, "runScriptOnNode");
      this.badNodes = checkNotNull(badNodes, "badNodes");
      this.goodNodes = checkNotNull(goodNodes, "goodNodes");
   }

   @Override
   public ExecResponse call() {
      checkState(runScriptOnNode != null, "runScriptOnNode must be set");
      checkState(!tainted, "this object is not designed to be reused: %s", toString());
      tainted = true;
      try {
         ExecResponse exec = runScriptOnNode.call();
         logger.debug("<< options applied node(%s)", runScriptOnNode.getNode().getId());
         logger.trace("<< script output for node(%s): %s", runScriptOnNode.getNode().getId(), exec);
         goodNodes.put(runScriptOnNode.getNode(), exec);
         return exec;
      } catch (Exception e) {
         logger.error(e, "<< problem applying options to node(%s): ", runScriptOnNode.getNode().getId(),
                  getRootCause(e).getMessage());
         badNodes.put(runScriptOnNode.getNode(), e);
      }
      return null;
   }

   @Override
   public String toString() {
      return MoreObjects.toStringHelper(this).add("runScriptOnNode", runScriptOnNode).add("goodNodes", goodNodes).add(
               "badNodes", badNodes).toString();
   }

},data_class

public ServiceDefinition[] findServicesByToolID(final String toolId) {
        try {
            ensureDiskCacheLoaded();
            accessLock.readLock().lock();

            final boolean returnAll = toolId == null || toolId.length() == 0;
            final List<ServiceDefinition> requestedDefinitions = new ArrayList<ServiceDefinition>();

            // Iterate the map of service types. Values are a map of service
            // instances.
            for (final Map<GUID, ServiceDefinition> mapServiceInstances : mapServices.values()) {
                for (final ServiceDefinition definition : mapServiceInstances.values()) {
                    /*
                     * NB! some service definitions in Dev12 QU1 may have null
                     * ToolID
                     */
                    if (returnAll || toolId.equalsIgnoreCase(definition.getToolID())) {
                        requestedDefinitions.add((ServiceDefinition) definition.clone());
                    }
                }
            }

            // Return null if no matching definitions were found.
            if (requestedDefinitions.size() == 0) {
                return null;
            }

            // Return an array of the matching service definitions.
            return requestedDefinitions.toArray(new ServiceDefinition[requestedDefinitions.size()]);
        } finally {
            accessLock.readLock().unlock();
        }
    },long_method

protected class StylingContentHandler extends AbstractXMLPipe {

        private int elementNesting;
        private SaxBuffer styling;

        public void setSaxFragment(SaxBuffer saxFragment) {
            styling = saxFragment;
        }

        public void recycle() {
            super.recycle();
            elementNesting = 0;
            styling = null;
        }

        public void startElement(String uri, String loc, String raw, Attributes a)
        throws SAXException {
            elementNesting++;
            super.startElement(uri, loc, raw, a);
        }

        public void endElement(String uri, String loc, String raw)
        throws SAXException {
            elementNesting--;
            if (elementNesting == 0) {
                styling.toSAX(getContentHandler());
            }
            super.endElement(uri, loc, raw);
        }
    },god_class

